pub unsafe fn compute_account_value_for_direction(
    result: *mut OptionUnitQty,
    user_state: *mut UserState,
    is_isolated: u8,
    asset_idx: u64,
    margin_mode: u32,
    oracle_data: *mut (),
) -> *mut OptionUnitQty {
    let _ = (user_state, is_isolated, asset_idx, margin_mode, oracle_data);
    (*result).value = 0;
    (*result).tag = 0;
    (*result).unit = 0;
    result
}
